// Transforma la respuesta del GA4 Data API a filas de web_traffic.
//
// Lee de cada item las dimensiones y métricas que GA4 devuelve, normaliza
// UTMs a lowercase kebab-case, parsea la fecha 'YYYYMMDD' → 'YYYY-MM-DD'
// y arma el payload que matchea el unique constraint:
//   (fecha, utm_source, utm_medium, utm_campaign, utm_content, landing_page)
//
// landing_page queda NULL — la query del funnel no la necesita.

const toIsoDate = (raw) => {
  const s = String(raw ?? '');
  if (/^\d{8}$/.test(s)) return `${s.slice(0, 4)}-${s.slice(4, 6)}-${s.slice(6, 8)}`;
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  return null;
};

const normalizeUtm = (raw) => {
  if (raw === null || raw === undefined) return null;
  const s = String(raw).trim().toLowerCase();
  if (!s || s === '(not set)' || s === '(none)') return null;
  return s
    .normalize('NFD')
    .replace(/[̀-ͯ]/g, '')
    .replace(/\s+/g, '-')
    .replace(/[^a-z0-9\-_().]/g, '');
};

const toInt = (v) => {
  const n = Number(v ?? 0);
  return Number.isFinite(n) ? Math.round(n) : 0;
};

const toFloat = (v) => {
  const n = Number(v ?? 0);
  return Number.isFinite(n) ? n : 0;
};

const output = [];
for (const item of items) {
  const r = item.json;
  const fecha = toIsoDate(r.date);
  if (!fecha) continue;

  output.push({
    json: {
      fecha,
      utm_source: normalizeUtm(r.sessionSource),
      utm_medium: normalizeUtm(r.sessionMedium),
      utm_campaign: normalizeUtm(r.sessionCampaignName),
      utm_content: null,
      utm_term: null,
      landing_page: null,
      sesiones: toInt(r.sessions),
      usuarios: toInt(r.totalUsers),
      usuarios_nuevos: toInt(r.newUsers),
      conversiones: toInt(r.conversions),
      eventos_clave: toInt(r.conversions),
      bounce_rate: toFloat(r.bounceRate),
      avg_session_duration: toFloat(r.averageSessionDuration),
      pageviews: toInt(r.screenPageViews),
    },
  });
}

return output;
